#include <bits/stdc++.h> 
using namespace std;
const int N=100005,base=31,mod=1000000007;
#define ull unsigned long long
int t,n,m;
string a,b;
ull hashh,has[N],tmp[N];
long long dp[N];
ull check(int l,int r)
{
	int len=r-l+1;
	return has[r]-has[l-1]*tmp[len];
}

int main()
{
	cin>>t;
	for(int j=1;j<=t;j++)
	{
		tmp[0]=1;
		cin>>a>>b;
		n=a.size();
		m=b.size();
		a=" "+a;
		b=" "+b;
		hashh=0;
		for(int i=1;i<=m;i++)
		{
			hashh=hashh*base+b[i];
		}
		for(int i=1;i<=n;i++)
		{
			has[i]=has[i-1]*base+a[i];
			tmp[i]=tmp[i-1]*base;
		}
		dp[0]=1;
		for(int i=1;i<=n;i++)
		{
			dp[i]=dp[i-1];
			if(i<m) continue;
			if(check(i-m+1,i)==hashh) dp[i]=(dp[i]+dp[i-m])%mod;
		}
		cout<<"Case #"<<j<<": "<<dp[n]<<'\n';
	}
	return 0;
}
